}

node.status({ fill: "green", shape: "dot", text: `${Object.keys(enrichedVars).length} vars chargées` });

// ---- 2. Supprimer l'ancienne variable enrichedVars du store par défaut ----
global.set("enrichedVars", undefined, storeDefault);

// ---- 3. Parcourir chaque variable et créer les globales typées ----
let totalVars = 0;
let totalInstances = 0;

Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || ["*"];
