// Cas 1 : message complet, on construit et retourne msg
if (modeData && optionsData !== undefined && optionsData !== null) {
    const mode = modeData.mode_Pilotage || "";
    const periph = modeData.choix_Periph || "";
    const optionsObj = optionsData || {};
    const regles = flow.get("regles") || [];

    const selectedOptionsArray = Object.keys(optionsObj).filter(k => optionsObj[k]);
    const optionsStr = selectedOptionsArray.length > 0
        ? selectedOptionsArray.join(", ")
        : "aucune option sélectionnée";

    function correspond(regle, mode, periph, optionsArray) {
        const opt = regle.options;
        const modeOk = (regle.mode === "*" || mode === regle.mode || mode.includes(regle.mode));
        const periphOk = (regle.periph === "*" || periph === regle.periph);
        let optionsOk = false;

        if (opt === "*") {
            optionsOk = true;
        } else if (Array.isArray(opt)) {
            if (opt.length === 0) {
                optionsOk = optionsArray.length === 0;
            } else {
                optionsOk = opt.every(o => optionsArray.includes(o));
            }
        }

        return modeOk && periphOk && optionsOk;
    }

    let complement = "";
    for (let regle of regles) {
        if (correspond(regle, mode, periph, selectedOptionsArray)) {
            complement = regle.message;
            break;
        }
    }

    // Stockage final
    flow.set("last_mode", mode);
    flow.set("last_periph", periph);
    flow.set("last_options", selectedOptionsArray);

