    // Découpage en chunks
    var configStr = JSON.stringify(defaultConfig);
    var chunkSize = 100;

    for (var i = 0; i < Math.ceil(configStr.length / chunkSize); i++) {
        var chunk = configStr.substring(i * chunkSize, (i + 1) * chunkSize);
