// Routage purement technique
if (msg.source === "UI") msg.topic = "PtoA";
else if (msg.source === "SYSTEM") msg.topic = "PtoA";
else if (msg.source === "VPIV") msg.topic = "AtoSP";
else msg.topic = "PtoSE";

return msg;

/**
