 */
msg.timestamp = Date.now();
msg.priority = "NORMAL";

// Détection de la source physique
if (msg.topic) {
    if (msg.topic.includes('/se')) msg.source = "SE";
    else if (msg.topic.includes('/a')) msg.source = "A";
}
msg.source = msg.source || "UI_INTERNAL";

return msg;

/**
 * PARSER ET ROUTEUR DE NATURE (CAT)
 * Gère le flux standard et le décapsulage STT
 */

// 1. VÉRIFICATION FORMATAIRE
let raw = msg.payload.toString().trim();
if (!raw.startsWith('$') || !raw.endsWith('#')) return null;

// 2. DÉCOMPOSITION VPIV
let content = raw.substring(1, raw.length - 1);
let parts = content.split(':');

let vpiv = {
    cat: parts[0],  
    var: parts[1],  
    inst: parts[2] || '*',
    prop: parts[3],
    val: parts[4]
};

// 3. GESTION SPÉCIFIQUE STT (Désencapsulation d'Intent)
// Format attendu : $I:STT:*:intent:{VAR:INST:PROP:VAL}#
if (vpiv.var === "STT" && vpiv.prop === "intent") {
    let capsule = vpiv.val.replace(/[{}]/g, "");
    let c = capsule.split(':');

    if (c.length >= 4) {
        msg.vpiv = {
            cat: "V", // Une intention vocale est traitée comme une commande
            var: c[0],
            inst: c[1],
            prop: c[2],
            val: c[3]
        };
        msg.source = "STT_VOICE";
        msg.priority = "HIGH";
        return msg; // Envoi direct au cerveau
    }
}

// 4. NORMALISATION DES TYPES (CSV -> Array ou Number)
if (vpiv.val.includes(',')) {
    vpiv.val = vpiv.val.split(',').map(v => isNaN(v) ? v : Number(v));
} else {
    vpiv.val = isNaN(vpiv.val) ? vpiv.val : (vpiv.val === "true" ? true : (vpiv.val === "false" ? false : Number(vpiv.val)));
}
msg.vpiv = vpiv;

// 5. LOGIQUE DE ROUTAGE ET MISE À JOUR MÉMOIRE (Global)
// Fonction utilitaire de MAJ Global
function updateGlobal(v) {
    let store = global.get(v.var) || {};
    store[v.prop] = v.val;
    global.set(v.var, store);
}

switch (vpiv.cat) {
    case "F": 
        // FLUX (Odom, Laisse, Gyro...) : Mise à jour UI directe et arrêt.
        updateGlobal(vpiv);
        return null; 

    case "I":
    case "E":
        // INFO ou EVENT : Mise à jour Réalité (UI) + Information Cerveau.
        updateGlobal(vpiv);
        if (vpiv.cat === "E") msg.priority = "CRITICAL";
        return msg;

    case "V":
        // COMMANDE (UI/STT) : Transmission Cerveau uniquement (Pas de MAJ Global ici).
        return msg;

    default:
        return null;
}

/**
 * ENCODEUR VPIV ET ROUTEUR HARDWARE
 */
let v = msg.vpiv || msg.payload;
if (!v.cat || !v.var) return null;

// Construction de la valeur String (gestion des tableaux)
let valStr = Array.isArray(v.val) ? v.val.join(',') : v.val;

// Formatage VPIV
msg.payload = `$${v.cat}:${v.var}:${v.inst || '*'}:${v.prop}:${valStr}#`;

// ROUTAGE MQTT (Choix du topic)
// Variables spécifiques au Smartphone Embarqué (SE)
const SE_VARS = ['CfgS', 'STT', 'Voice', 'CamSE', 'MicroSE', 'Appli', 'Sys'];

if (SE_VARS.includes(v.var) || v.var.startsWith('CfgS')) {
    msg.topic = "rz/vpiv/in/se";
} else {
    msg.topic = "rz/vpiv/in/a"; // Par défaut vers Arduino
}

return msg;

// ============================================
// RZ_VPIV_Encoder_Dispatcher_V1
// Encode chaque action en trame VPIV
// ============================================

if (!msg.command || !Array.isArray(msg.command.actions)) {
    return null;
}

let outArduino = [];
let outSE = [];

msg.command.actions.forEach(action => {
    // Sécurité minimale
    if (!action.cat || !action.module || !action.prop || action.value === undefined) {
        return;
    }

    let inst = action.inst || "*";
    let vpiv = `$${action.cat}:${action.module}:${action.prop}:${inst}:${action.value}#`;

    let outMsg = {
        payload: vpiv,
        vpiv: {
            cat: action.cat,
            module: action.module,
            prop: action.prop,
            inst: inst,
            value: action.value
        }
    };

    if (action.device === "ARDUINO") {
        outArduino.push(outMsg);
    } else if (action.device === "SE") {
        outSE.push(outMsg);
    }
});

return [outArduino, outSE];

