    if (varToDelete && enrichedVars[varToDelete]) {
        // 1. Suppression RAM
        delete enrichedVars[varToDelete];
        global.set("enrichedVars", enrichedVars);

        // 2. Persistance Disque immédiate
        try {
            if (Object.keys(enrichedVars).length === 0) {
                // Optionnel : protéger si on veut interdire de supprimer la DERNIÈRE variable
                // ou simplement autoriser un fichier vide :
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: {}, lastUpdate: new Date().toISOString() }, null, 4));
            } else {
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: enrichedVars, lastUpdate: new Date().toISOString() }, null, 4));
            }
            node.warn(`🗑️ Variable ${varToDelete} supprimée (RAM & Disque)`);
        } catch (err) {
            node.error("❌ Erreur lors de la suppression disque : " + err.message);
        }
    }

    flow.set("varSelected", null);
    msg.payload = "refresh";
    return msg;
}
return null;

// open-dialog -> Preparation d'une Boite de Dialogue Suppression
// les actions dans ui-notification doivent être configuré selon un schéma précis
const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.payload = {
        type: "warning", 
        title: "Aucune variable",
        text: "Veuillez sélectionner une variable à supprimer.",
        duration: 3000
    };
    return msg;
}

flow.set("pendingDeletion", varSelected);
// gestion dynamique du ui-notification, les mots clefs de ui-update sont spécifique au noeud
msg.payload = {
    type: "warning",
    title: "Confirmation suppression",
    text: `Voulez-vous vraiment supprimer la variable "<strong>${varSelected}</strong>" ?`,
    displayTime: 0, // Ne pas fermer automatiquement
    ui_update: {
        allowConfirm: true,
        allowDismiss: true,
        confirmText: "✅ Supprimer",
        dismissText: "❌ Annuler"
    }
};

return msg;

/*******************************************************************************
 * NOM DU NŒUD : chargeEnrichedVarsToMemory
 * RÔLE : Charger le dictionnaire maître en RAM au lancement de l'UI
 * DERNIÈRE MODIF : 24/03/2026 - Cohérence SF_Init_1 / nodeFs
 ******************************************************************************/

// --- CONFIGURATION ---
const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

// --- FONCTIONS DE COHÉRENCE (Identiques à SF_Init_1) ---
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        default: return "";
    }
}

// 1. TENTATIVE DE RÉCUPÉRATION RAM
let enrichedVars = global.get("enrichedVars");

// 2. SI RAM VIDE : LECTURE PHYSIQUE DU FICHIER (nodeFs)
if (!enrichedVars || Object.keys(enrichedVars).length === 0) {
    try {
        if (nodeFs.existsSync(filePath)) {
            const rawData = nodeFs.readFileSync(filePath, 'utf8');
            const parsed = JSON.parse(rawData);
            enrichedVars = parsed.enrichedVars || {};

            // On peuple la RAM pour que le reste de l'UI fonctionne immédiatement
            global.set("enrichedVars", enrichedVars);
            node.status({ fill: "blue", shape: "dot", text: "Chargé depuis Disque" });
        } else {
            node.error("🚨 CRITIQUE : globalSave.json introuvable !");
            node.status({ fill: "red", shape: "ring", text: "Fichier absent" });
            return null;
        }
    } catch (e) {
        node.error("🚨 Erreur de lecture : " + e.message);
        return null;
    }
} else {
    node.status({ fill: "green", shape: "dot", text: "Données RAM prêtes" });
}

// 3. TRANSFERT VERS LE FLOW UI
msg.payload = enrichedVars;
return msg;

info:
// Les variables sont stockées dans deux types de stockage : "default" et "file".
// Ce nœud synchronise les variables globales avec enrichedVars.
// Il met à jour enrichedVars avec les variables globales actuelles
// et s'assure que chaque variable suit la nouvelle structure définie.

// Les variables sont structurées avec des propriétés comme nomVarG, instances, propriétés, etc.
// La fonction gère également la restauration des variables globales manquantes depuis enrichedVars.
// Elle prend en compte les instances et les sous-variables pour une synchronisation cohérente.

func:
/*******************************************************************************
 * NOM DU NŒUD : routerAction
 * RÔLE : Intercepter le clic sur le tableau et préparer les formulaires
 ******************************************************************************/

let action = msg.payload.action; // "editBase", "editValues", "delete"
let prop = msg.payload.row;     // Les données de la ligne cliquée

// --- CAS 1 : CRÉATION D'UNE NOUVELLE PROPRIÉTÉ ---
// On détecte la ligne virtuelle que tu as ajoutée dans 'prepaTableauProprietes'
if (prop.nomP === 'NouvelleP' || prop._isNew === true) {

    // On vide la référence de renommage pour indiquer une CRÉATION
    flow.set("propOriginalName", null);

    // On prépare un objet vide pour le formulaire "Configuration de la Structure"
    msg.payload = {
        nomP: "",
        nomCpletP: "",
        typeP: "string",
        descriptionP: ""
    };

    msg.topic = "new_prop"; // Optionnel, pour info
    // On envoie vers le formulaire de structure (Base)
    return [msg, null, null]; 
}

// --- CAS 2 : PROPRIÉTÉ EXISTANTE ---

// On mémorise le nom actuel pour gérer les renommages plus tard
flow.set("propOriginalName", prop.nomP);

if (action === "delete") {
    msg.topic = "delete";
    msg.prop = prop;
    return [null, null, msg]; // Vers SauvResultatActions
} 

if (action === "editBase") {
    // On prépare le formulaire "Configuration de la Structure" avec les données existantes
    msg.payload = {
        nomP: prop.nomP,
        nomCpletP: prop.nomCpletP || "",
        typeP: prop.typeP,
        descriptionP: prop.descriptionP || ""
    };
    return [msg, null, null]; // Vers Formulaire Base
}

if (action === "editValues") {
    // On prépare le formulaire "Valeurs par Instance"
    // On passe l'objet valeurs complet
    msg.payload = prop.valeurs || {};
    msg.propName = prop.nomP; 
    return [null, msg, null]; // Vers Formulaire Valeurs
}

return null;

// Prépare l'affichage du tableau des propriétés
let varSelected = flow.get('varSelected') || null;
let enrichedVars = global.get('enrichedVars', 'file') || {};
let variable = enrichedVars[varSelected] || {};
let propSelected = flow.get('propSelected') || null;
let infoAction = flow.get('infoAction') || null;

console.log("prepareTableauProprietes - varSelected:", varSelected);

// Si aucune variable sélectionnée ou nouvelle variable
if (!varSelected || varSelected === "new") {
    msg.payload = {
        proprietes: [],  // ← Tableau VIDE (pas de ligne "NouvelleP")
        propSelected: null,
        instances: [],
        variable: { nomVarG: varSelected === "new" ? "Nouvelle variable" : "Aucune variable sélectionnée" }
    };
    msg.info = varSelected === "new"
        ? "Nouvelle variable - définissez d'abord la variable"
        : "Sélectionnez une variable dans le tableau";
    return msg;
}

// Traitement normal pour variable existante
if (msg.topic == "initialisePropriete") {
    flow.set("propSelected", null);
}

if (msg.topic == "refresh") {
    flow.set("propSelected", null);
}

let proprietes = (variable.proprietes || []).map(p => ({
    nomP: p.nomP,
    nomCpletP: p.nomCpletP,
    typeP: p.typeP,
    schema: p.schema || null,
    valeurs: p.valeurs || {},
    defaut: (p.valeurs && p.valeurs['*'] !== undefined) ? p.valeurs['*'] : null,
    useValueList: p.useValueList || false,
    valueList: p.valueList || [],
    _locked: p._locked || false
}));

// Ajouter une ligne pour nouvelle propriété UNIQUEMENT si variable existe
if (varSelected && varSelected !== "new") {
    proprietes.push({
        nomP: 'NouvelleP',
        nomCpletP: 'New',
        typeP: null,
        schema: null,
        valeurs: { '*': null },
        _isNew: true
    });
}

msg.payload = {
    proprietes: proprietes,
    propSelected: propSelected,
    instances: (variable.instances || []).filter(i => i !== '*'),
    variable: { nomVarG: variable.nomVarG || varSelected }
};

msg.info = 'Variable:' + varSelected + ' - ' + infoAction + (propSelected ? propSelected : "choisir une propriété");
return msg;

/*******************************************************************************
 * NOM DU NŒUD : SauvResultatActions
 * RÔLE : Enregistrement définitif (Structure ou Valeurs)
 ******************************************************************************/

const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

let enriched = global.get('enrichedVars') || {};
let varSelected = flow.get('varSelected');
let originalName = flow.get("propOriginalName");

if (!enriched[varSelected]) return null;
let variable = enriched[varSelected];
variable.proprietes = variable.proprietes || [];

// --- LOGIQUE D'ENREGISTREMENT ---
if (msg.topic === "saveBase") {
    // Cas : Modification de la structure (Formulaire Base)
    let p = msg.payload; 
    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);

    let updatedProp = {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP,
        typeP: p.typeP,
        descriptionP: p.descriptionP,
        // On conserve les valeurs existantes ou on initialise si création
        valeurs: (idx >= 0) ? variable.proprietes[idx].valeurs : { "*": "" }
    };

    if (idx >= 0) {
        variable.proprietes[idx] = updatedProp;
    } else {
        variable.proprietes.push(updatedProp);
    }
} 
else if (msg.topic === "saveValues") {
    // Cas : Modification des données (Formulaire Valeurs par instance)
    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);
    if (idx >= 0) {
        // msg.payload contient ici le dictionnaire { instance: valeur }
        variable.proprietes[idx].valeurs = msg.payload;
    }
}
else if (msg.topic === "delete") {
    variable.proprietes = variable.proprietes.filter(pr => pr.nomP !== msg.prop.nomP);
}

// --- PERSISTANCE ---
global.set('enrichedVars', enriched);

try {
    const out = { enrichedVars: enriched, lastUpdate: new Date().toISOString() };
    nodeFs.writeFileSync(filePath, JSON.stringify(out, null, 4), 'utf8');
    node.status({fill:"green", shape:"dot", text:"💾 Synchronisé"});
} catch (err) {
    node.error("Erreur Disque : " + err.message);
}

// Nettoyage et rafraîchissement UI
flow.set("propOriginalName", null);
msg.topic = "refresh";
return msg;

// Noeud "Gestion Sélection Automatique" - VERSION CORRIGÉE
let varSelected = msg.payload;

console.log("Gestion Sélection Automatique - varSelected:", varSelected);

if (varSelected && varSelected !== "new") {
    // Variable existante sélectionnée
    flow.set('varSelected', varSelected);
    console.log("Variable sélectionnée automatiquement:", varSelected);

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "refresh",
        payload: varSelected,
        info: `✅ Vous êtes sur la variable : ${varSelected}`
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: varSelected
    };

    return [formMsg, tableauMsg];

} else if (varSelected === "new") {
    // Nouvelle variable
    flow.set('varSelected', "new");

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "newVarG",
        info: "➕ Création d'une nouvelle variable.",
        payload: {
            nomVarG: "",
            nomCpletVarG: "",
            instances: "*",
            descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
            dateUpdateVarG: new Date().toISOString()
        }
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: "new"
    };

    return [formMsg, tableauMsg];

} else {
    // Aucune sélection
    return [null, null];
}

// Noeud "Initialisation Page"
// S'exécute au chargement de la page pour reset l'état

// Reset les sélections au chargement
flow.set('varSelected', null);
flow.set('propSelected', null);
flow.set('infoAction', "Sélectionnez une variable");

// Préparer un tableau vide
msg.payload = {
    proprietes: [{
        nomP: 'NouvelleP',
        nomCpletP: 'New',
        typeP: null,
        schema: null,
        valeurs: { '*': null },
        _isNew: true
    }],
    propSelected: null,
    instances: [],
    variable: { nomVarG: "Aucune variable sélectionnée" }
};
msg.info = "Sélectionnez une variable dans le tableau";

return msg;

// Voir ce qui existe dans le stockage fichier
let fileData = global.get("enrichedVars", "file");
node.warn("Données dans le fichier: " + JSON.stringify(fileData));

// Voir tous les keys disponibles (si supporté)
try {
    let keys = global.keys("file");
    node.warn("Clés disponibles dans le fichier: " + JSON.stringify(keys));
} catch(e) {
    node.warn("keys() non supporté: " + e.message);
}

/* Le nœud ui-notification envoie un message avec msg.payload contenant :
   - "confirm_clicked" si l'utilisateur clique sur "✅ Supprimer".
   - "dismiss_clicked" si l'utilisateur clique sur "❌ Annuler".
*/
if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");

    if (!varToDelete) {
        msg.info = "⚠️ Aucune variable en attente de suppression.";
        return msg;
    }

    // Suppression
    let enrichedVars = global.get("enrichedVars", "file") || {};
    delete enrichedVars[varToDelete];
    delete enrichedVars[""];
    global.set("enrichedVars", enrichedVars, "file");
    global.set(varToDelete, undefined, "default");
    flow.set("varSelected", "none");
    flow.set("pendingDeletion", null);

    msg.payload = "none";
    msg.info = `✅ Variable "${varToDelete}" supprimée.`;
    msg.notification = {
        type: "success",
        title: "✅ Supprimée",
        text: `Variable "${varToDelete}" supprimée avec succès.`,
        duration: 3000
    };

} else if (msg.payload === "dismiss_clicked") {
    flow.set("pendingDeletion", null);
    msg.info = "❌ Suppression annulée.";
    msg.notification = {
        type: "info",
        title: "❌ Annulée",
        text: "Suppression annulée.",
        duration: 3000
    };
}

return msg;

// Dans le noeud "routerAction" - version corrigée
let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars', 'file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*');

if (action) flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);

// CORRECTION : Récupérer la propriété COMPLÈTE depuis la variable
let completeProp = prop;
if (prop.nomP && !prop._isNew) {
    // Chercher la propriété complète dans la variable
    let foundProp = (variable.proprietes || []).find(p => p.nomP === prop.nomP);
    if (foundProp) {
        completeProp = foundProp;
    }
}

// Gestion de l'éditeur Base (nouveau ou modification)
if (action === 'base') {
    // Si c'est une nouvelle propriété (_isNew = true), on envoie un objet vide
    // Sinon, on envoie la propriété complète
    let propData = prop._isNew ? {} : completeProp;

    return [{
        topic: 'openEditor',
        editor: 'base',
        prop: propData,
        instances: instances,
        originalName: prop._isNew ? null : prop.nomP
    }, null, null];
}
// Gestion de l'éditeur Valeurs
else if (action === 'valeurs') {
    return [null, {
        topic: 'openEditor',
        editor: 'valeurs',
        prop: completeProp,  // ← Propriété COMPLÈTE avec useValueList et valueList
        instances: instances,
        originalName: prop.nomP
    }, null];
}
else if (action === 'delete') { 
    return [null, null, { topic: 'delete', prop }]; 
}
return null;

// Chargement exemple de variables complexes

let variables = {
    EXPR: {
        type: "complex",
        properties: {
            "Bonjour": {
                actions: [
                    {
                        device: "app-SE",
                        type: "TTS",
                        value: "Bonjour"
                    }
                ]
            },
            "Oui": {
                actions: [
                    {
                        device: "app-SE",
                        type: "TTS",
                        value: "Oui"
                    },
                    {
                        device: "app-A",
                        type: "LRUB",
                        target: "ar_gd0",
                        color: "orange",
                        mode: "blink"
                    }
                ]
            }
        }
    }
};

global.set("variables", variables);

global.set("modeRZ", "VEILLE");
global.set("emergency", false);

return msg;

let vars = global.get("variables") || {};
let v = msg.payload.variable;
let p = msg.payload.property;

if (!vars[v]) {
    msg.error = "UNKNOWN_VARIABLE";
    return [null, msg];
}

if (!vars[v].properties[p]) {
    msg.error = "UNKNOWN_PROPERTY";
    return [null, msg];
}

msg.plan = {
    intent: `${v}:${p}`,
    actions: vars[v].properties[p].actions,
    meta: {
        source: msg.payload.source || "UNKNOWN",
        priority: "NORMAL"
    }
};

return [msg, null];

let modeRZ = global.get("modeRZ");
let emergency = global.get("emergency");

let accepted = [];
let refused = [];

for (let act of msg.plan.actions) {

    if (act.type === "MTR") {
        if (emergency === true) {
            refused.push({action: act, reason: "EMERGENCY"});
            continue;
        }
        if (!["VEILLE", "DEPLACEMENT"].includes(modeRZ)) {
            refused.push({action: act, reason: "MODE_INCOMPATIBLE"});
            continue;
        }
    }

    if (act.type === "SERVO") {
        if (!["FIXE", "VEILLE", "DEPLACEMENT"].includes(modeRZ)) {
            refused.push({action: act, reason: "MODE_INCOMPATIBLE"});
            continue;
        }
    }

    accepted.push(act);
}

if (accepted.length === 0) {
    msg.status = "REFUSED";
    msg.refused = refused;
    return [null, msg];
}

msg.status = "ACCEPTED";
msg.acceptedActions = accepted;
return [msg, null];

let vpivs = [];

for (let act of msg.acceptedActions) {
    vpivs.push({
        vpiv: {
            app: act.device,
            var: act.type,
            prop: act.target || "",
            value: act.value || {
                color: act.color,
                mode: act.mode
            }
        }
    });
}

msg.vpivs = vpivs;
return msg;

const selected = msg.payload?.row;
if (!selected || !selected.id) return null;
flow.set("ruleSelected", selected.id);
msg.payload = `🧠 Règle sélectionnée : ${selected.name}`;
return msg;

let rules = global.get("rules", "file") || [];

if (!Array.isArray(rules)) {
    rules = [];
    global.set("rules", rules, "file");
}

// Préparer la table
msg.payload = rules.map(r => ({
    id: r.id,
    name: r.name,
    type: r.type || "",
    description: r.description || "",
    enabled: r.enabled ? "✅" : "❌",
    modified: r.lastModified?.slice(0, 19).replace("T", " ") || ""
}));

return msg;

let rules = global.get("rules", "file") || [];

function generateId() {
    return 'r' + Math.random().toString(36).substring(2, 6);
}

const newRule = {
    id: generateId(),
    name: "Nouvelle règle",
    description: "",
    type: "",
    enabled: true,
    triggers: [],
    conditions: [],
    actions: [],
    lastModified: new Date().toISOString()
};

rules.push(newRule);
global.set("rules", rules, "file");

msg.payload = rules.map(r => ({
    id: r.id,
    name: r.name,
    type: r.type || "",
    description: r.description || "",
    enabled: r.enabled ? "✅" : "❌",
    modified: r.lastModified?.slice(0, 19).replace("T", " ") || ""
}));
return msg;

const rules = global.get("rules") || [];

function testCondition(cond, varG) {
    const { var: varName, instance, property, operator, value } = cond;
    const val = varG[varName]?.[instance]?.[property];
    switch (operator) {
        case "==": return val === value;
        case "!=": return val !== value;
        case ">": return val > value;
        case "<": return val < value;
        case ">=": return val >= value;
        case "<=": return val <= value;
        default: return false;
    }
}

const varG = global.get("enrichedVars") || {};
const outputMsgs = [];

for (const rule of rules) {
    if (!rule.enabled) continue;

    const allConditionsOK = rule.conditions.every(cond => testCondition(cond, varG));

    if (allConditionsOK) {
        for (const action of rule.actions) {
            const outMsg = {
                payload: action.value || action.payload || null,
                topic: action.topic || null,
                info: action.info || `Action de la règle: ${rule.name}`,
                ruleId: rule.id,
                ruleName: rule.name,
                actionType: action.type,
                target: action.target
            };
            outputMsgs.push(outMsg);
        }
    }
}

return [outputMsgs];

const ruleId = flow.get("ruleSelected");
if (!ruleId) return null;
const rules = global.get("rules", "file") || [];
const rule = rules.find(r => r.id === ruleId);
if (!rule) return null;
msg.payload = rule;
return msg;

let rules = global.get("rules", "file") || [];

if (msg.topic === "saveRule") {
    const updated = msg.payload;
    rules = rules.filter(r => r.id !== updated.id);
    rules.push(updated);
    global.set("rules", rules, "file");
    msg.payload = `✅ Règle ${updated.name} enregistrée`;
    return [msg, null];
}

if (msg.topic === "deleteRule") {
    const id = msg.payload;
    rules = rules.filter(r => r.id !== id);
    global.set("rules", rules, "file");
    msg.payload = `🗑 Règle supprimée`; 
    return [msg, null];
}

if (msg.topic === "reloadRule") {
    const rule = rules.find(r => r.id === msg.payload);
    if (!rule) return null;
    msg.payload = rule;
    return [null, msg];
}

return null;

// 📥 enrichedVars stocké en global (structure connue)
const varG = global.get("enrichedVars", "file") || {};
const rules = global.get("rules", "file") || [];

function getVal(varName, instance, property) {
    return varG?.[varName]?.proprietesByInstance?.valeurs?.[instance]?.[property];
}

function testCondition(cond) {
    const { var: varName, instance, property, operator, value } = cond;
    const val = getVal(varName, instance, property);
    switch (operator) {
        case "==": return val == value;
        case "!=": return val != value;
        case ">": return val > value;
        case "<": return val < value;
        case ">=": return val >= value;
        case "<=": return val <= value;
        default: return false;
    }
}

const outputs = [];

for (const rule of rules) {
    if (!rule.enabled) continue;
    if (!rule.conditions || rule.conditions.length === 0) continue;

    const ok = rule.conditions.every(testCondition);
    if (ok) {
        for (const action of rule.actions) {
            const out = {
                payload: action.value || null,
                topic: action.topic || null,
                info: action.info || `Action ${action.type}`,
                ruleId: rule.id,
                ruleName: rule.name,
                actionType: action.type,
                target: action.target,
                instance: action.instance,
                property: action.property
            };
            outputs.push(out);
        }
    }
}

return [outputs];

// Supprimer des propriétés inutiles qui peuvent interférer
delete msg.group;
delete msg.tab;

// Forcer l'affichage de l'onglet nommé "P_Admin"
msg.payload = {
    page: "P_admin-ReglesV2"
};

return msg;

let regles = global.get("reglesVars", "file") || [];
let tableau = regles.map((r, i) => ({ index: i, ...r }));
msg.payload = tableau;
return msg;

global.set("reglesVars", msg.payload, "file");
msg.payload = `🆕 ${msg.payload.length} règles initialisées.`;
return msg;

let regles = global.get("reglesVars", "file") || [];
let index = msg.payload;
let selected = regles[index];

if (index === "new" || selected === undefined) {
    msg.payload = {
        var1: "", val1: "",
        var2: "", val2: "",
        var3: "", val3: "",
        action: "",
        type: "affichage"
    };
} else {
    msg.payload = selected;
    msg.payload._index = index;
}
return msg;

let regles = global.get("reglesVars", "file") || [];
let form = msg.payload;

if (form._index !== undefined) {
    regles[form._index] = form;
} else {
    regles.push(form);
}

global.set("reglesVars", regles, "file");
msg.payload = "✅ Règle enregistrée.";
return msg;

let regles = global.get("reglesVars", "file") || [];
let tableau = regles.map((r, i) => ({ index: i, ...r }));
msg.payload = tableau;
return msg;

try {
    let data = JSON.parse(msg.payload);
    if (Array.isArray(data)) {
        global.set("reglesVars", data, "file");
        msg.payload = `✅ ${data.length} règles importées`;
    } else {
        msg.payload = "❌ Format invalide (attendu tableau)";
    }
} catch(e) {
    msg.payload = "❌ Erreur de parsing : " + e.message;
}
return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};

msg.options = Object.keys(enrichedVars)
    .map(key => ({
        label: key,
        value: key
    }));

// Ajouter l'option de création
msg.options.push({ label: "➕ nouvelle-var", value: "new" });

msg.topic = "🔽 Liste des variables disponibles";
return msg;

let regleToDelete = flow.get("regleToDelete");
let reglesVars = global.get("reglesVars", "file") || {};

if (!regleToDelete) {
    msg.payload = "⚠️ Aucune variable sélectionnée";
    return msg;
}

if (reglesVars[regleToDelete]) {
    delete reglesVars[regleToDelete];
    global.set(reglesVars, undefined, "default");
    global.set("reglesVars", reglesVars, "file");
    msg.payload = `🗑️ "${regleToDelete}" supprimée avec succès`;
} else {
    msg.payload = `❌ "${regleToDelete}" n'existe pas`;
}

return msg;

let regles = global.get("reglesVars", "file") || [];
let tableau = regles.map((r, i) => ({ index: i, ...r }));
msg.payload = tableau;
return msg;

let regles = global.get("reglesVars", "file") || [];
let index = null;

// Cas sélection via tableau (payload = array)
if (Array.isArray(msg.payload) && msg.payload[0] && msg.payload[0].data && typeof msg.payload[0].data.index !== "undefined") {
    index = msg.payload[0].data.index;
} else if (typeof msg.payload === "number") {
    index = msg.payload;
}

let selected = regles[index];

if (index === "new" || selected === undefined) {
    msg.payload = {
        var1: "", val1: "",
        var2: "", val2: "",
        var3: "", val3: "",
        action: "",
        type: "affichage"
    };
} else {
    msg.payload = selected;
    msg.payload._index = index;
}
return msg;

// Supprimer des propriétés inutiles qui peuvent interférer
delete msg.group;
delete msg.tab;

// Forcer l'affichage de l'onglet nommé "P_Admin"
msg.payload = {
    page: "P_admin-Regles"
};

return msg;

let x = msg.payload.x;   // joystick: -1..1
let y = msg.payload.y;   // -1..1

let v = Math.round(-y*100);
let omega = Math.round(x*100);

let A = flow.get("accelA") || 1;

msg.payload = `$V:Mtr:*:cmd:${v},${omega},${A}#`;
return msg;
